diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..c0ba744c7857 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8633,14 +8633,36 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   Constant *RHSC;
   if (match(Op0, m_Instruction(LHSI)) && match(Op1, m_Constant(RHSC))) {
     switch (LHSI->getOpcode()) {
-    case Instruction::Select:
+    case Instruction::Select: {
       // fcmp eq (cond ? x : -x), 0 --> fcmp eq x, 0
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp ord_pred (select (fcmp ord X, 0), X, 0), C --> fcmp ord_pred X, C
+      // if fcmp ord_pred 0, C is false.
+      // For ordered predicates, both sides give false for NaN input.
+      if (FCmpInst::isOrdered(Pred)) {
+        Value *Cond, *Cond0, *Cond1;
+        const APFloat *C;
+        CmpPredicate SelectPred;
+        if (match(LHSI, m_Select(m_Value(Cond), m_Value(X), m_AnyZeroFP())) &&
+            match(Cond, m_FCmp(SelectPred, m_Value(Cond0), m_Value(Cond1))) &&
+            SelectPred == FCmpInst::FCMP_ORD &&
+            Cond0 == X && match(Cond1, m_AnyZeroFP()) &&
+            match(RHSC, m_APFloat(C))) {
+          // Check that comparing 0 against C gives false for this predicate.
+          Constant *Zero = Constant::getNullValue(X->getType());
+          Constant *CVal = ConstantFP::get(X->getType(), *C);
+          if (Constant *Res = ConstantFoldCompareInstOperands(
+                  Pred, Zero, CVal, DL))
+            if (match(Res, m_ZeroInt()))
+              return replaceOperand(I, 0, X);
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;
+    }
     case Instruction::FSub:
       if (LHSI->hasOneUse())
         if (Instruction *NV = foldFCmpFSubIntoFCmp(I, LHSI, RHSC, *this))

